// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getUsers,
  getApprovedCaptains,
  getPendingCaptains,
  getRides,
  approveCaptain,
  rejectCaptain,
} from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext";
import {
  AppBar,
  Toolbar,
  Box,
  Typography,
  Button,
  CircularProgress,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  Card,
  CardContent,
  Grid,
  Paper,
  Tabs,
  Tab,
  Stack,
  Link,
} from "@mui/material";

// Icons (changed for a fresh UI look)
import GroupsIcon from "@mui/icons-material/Groups";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import HourglassTopIcon from "@mui/icons-material/HourglassTop";
import CommuteIcon from "@mui/icons-material/Commute";

export default function AdminDashboard() {
  const { logout } = useAuth();

  const [overview, setOverview] = useState({
    users: 0,
    captains: 0,
    pendingCaptains: 0,
    rides: 0,
  });

  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Fetch overview
  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data.data);
    } catch (err) {
      console.error(err);
      setError("Failed to load overview");
    }
  };

  // Fetch table data
  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      switch (type) {
        case "users":
          res = await getUsers();
          break;
        case "captains":
          res = await getApprovedCaptains();
          break;
        case "pending":
          res = await getPendingCaptains();
          break;
        case "rides":
          res = await getRides();
          break;
        default:
          res = { data: { data: [] } };
      }
      setData(res?.data?.data || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data");
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  // Approve captain
  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to approve captain");
    }
  };

  // Reject captain
  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to reject captain");
    }
  };

  useEffect(() => {
    fetchOverview();
  }, []);

  // Dashboard cards
  const cards = [
    { label: "Users", value: overview.users, icon: <GroupsIcon fontSize="large" />, type: "users" },
    { label: "Approved Captains", value: overview.captains, icon: <VerifiedUserIcon fontSize="large" />, type: "captains" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <HourglassTopIcon fontSize="large" />, type: "pending" },
    { label: "Rides", value: overview.rides, icon: <CommuteIcon fontSize="large" />, type: "rides" },
  ];

  return (
    <Box sx={{ flexGrow: 1, bgcolor: "#f7f9fc", minHeight: "100vh" }}>
      {/* Header */}
      <AppBar position="static" sx={{ bgcolor: "#2c3e50", mb: 4 }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between" }}>
          <Typography variant="h6" fontWeight="bold">
            Admin Dashboard
          </Typography>
          <Button variant="contained" color="error" onClick={logout}>
            Logout
          </Button>
        </Toolbar>
      </AppBar>

      {/* Content */}
      <Box maxWidth="1200px" mx="auto" px={3} pb={5}>
        {/* Tabs */}
        <Paper elevation={2} sx={{ borderRadius: 3, mb: 4 }}>
          <Tabs
            value={activeTab}
            onChange={(e, val) => {
              setData([]);
              if (val === "overview") {
                fetchOverview();
              } else {
                fetchData(val);
              }
              setActiveTab(val);
            }}
            indicatorColor="primary"
            textColor="primary"
            variant="fullWidth"
          >
            <Tab label="Overview" value="overview" />
            <Tab label="Users" value="users" />
            <Tab label="Approved Captains" value="captains" />
            <Tab label="Pending Captains" value="pending" />
            <Tab label="Rides" value="rides" />
          </Tabs>
        </Paper>

        {/* Overview Section */}
        {activeTab === "overview" && (
          <Grid container spacing={3}>
            {cards.map((card) => (
              <Grid item xs={12} sm={6} md={3} key={card.label}>
                <Card
                  sx={{
                    textAlign: "center",
                    borderRadius: 3,
                    boxShadow: 2,
                    p: 2,
                    transition: "0.3s",
                    "&:hover": { boxShadow: 6, transform: "translateY(-5px)" },
                  }}
                >
                  <CardContent>
                    <Box color="primary.main" mb={1}>
                      {card.icon}
                    </Box>
                    <Typography variant="subtitle1" fontWeight="bold">
                      {card.label}
                    </Typography>
                    <Typography variant="h5" fontWeight="bold">
                      {card.value}
                    </Typography>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}

        {/* Error / Loading */}
        {loading && (
          <Box display="flex" justifyContent="center" mt={4}>
            <CircularProgress />
          </Box>
        )}
        {error && (
          <Typography color="error" textAlign="center" mt={2}>
            {error}
          </Typography>
        )}

        {/* Data Tables */}
        {!loading && data.length > 0 && activeTab !== "overview" && (
          <Paper sx={{ p: 3, borderRadius: 3, boxShadow: 2, mt: 4 }}>
            <Typography variant="h6" mb={2} fontWeight="bold">
              {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} Details
            </Typography>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Name</TableCell>
                  <TableCell>Email</TableCell>
                  <TableCell>Mobile</TableCell>
                  <TableCell>Role</TableCell>
                  {(activeTab === "captains" || activeTab === "pending") && <TableCell>Documents</TableCell>}
                  {activeTab === "pending" && <TableCell align="center">Actions</TableCell>}
                  {activeTab === "rides" && (
                    <>
                      <TableCell>Rider</TableCell>
                      <TableCell>Captain</TableCell>
                      <TableCell>Pickup</TableCell>
                      <TableCell>Drop</TableCell>
                      <TableCell>Status</TableCell>
                    </>
                  )}
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((item) => (
                  <TableRow key={item._id}>
                    <TableCell>{item.fullName || "-"}</TableCell>
                    <TableCell>{item.email || "-"}</TableCell>
                    <TableCell>{item.mobile || "-"}</TableCell>
                    <TableCell>{item.role || "-"}</TableCell>

                    {(activeTab === "captains" || activeTab === "pending") && (
                      <TableCell>
                        {item.documents?.length > 0 ? (
                          item.documents.map((doc, idx) => (
                            <Box key={idx}>
                              <Link href={doc.url} target="_blank" rel="noopener">
                                {doc.name || `Document ${idx + 1}`}
                              </Link>
                            </Box>
                          ))
                        ) : (
                          "-"
                        )}
                      </TableCell>
                    )}

                    {activeTab === "pending" && (
                      <TableCell align="center">
                        <Stack direction="row" spacing={1} justifyContent="center">
                          <Button
                            size="small"
                            color="success"
                            variant="outlined"
                            onClick={() => handleApprove(item._id)}
                          >
                            Approve
                          </Button>
                          <Button
                            size="small"
                            color="error"
                            variant="outlined"
                            onClick={() => handleReject(item._id)}
                          >
                            Reject
                          </Button>
                        </Stack>
                      </TableCell>
                    )}

                    {activeTab === "rides" && (
                      <>
                        <TableCell>{item.riderId?.fullName || "-"}</TableCell>
                        <TableCell>{item.captainId?.fullName || "-"}</TableCell>
                        <TableCell>{item.pickup || "-"}</TableCell>
                        <TableCell>{item.drop || "-"}</TableCell>
                        <TableCell>{item.status || "-"}</TableCell>
                      </>
                    )}
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Paper>
        )}

        {!loading && data.length === 0 && activeTab !== "overview" && (
          <Typography textAlign="center" mt={3}>
            No data found
          </Typography>
        )}
      </Box>
    </Box>
  );
}
